        HEY_YOU_RE_THAT_FAMOUS_ADVENTURER                                       = 10089,  -- Hey! You're that famous adventurer, %!
        YIPPEE_THIS_IS_MY_LUCKY_DAY                                             = 10090,  -- Yippee! This is my lucky day!
        LET_ME_INTRODUCE_MYSELF_I_AM_FROM_THE                                   = 10091,  -- Let me introduce myself. I am from the Rhinostery in Windurst. I do research on various living things.
        AND_I_M_THE_BESTY_WESTY_THEY_VE                                         = 10092,  -- And I'm the besty-westy they've got! I've been looking into phenomena at a certain place.
        WHAT_PHENOMENA_YOU_ASK_WELL_THERE_ARE_THESE                             = 10093,  -- What phenomena, you ask? Well, there are these giant crystals, you see! And from those crystals, a strangey-wangey power is constantly pouring forth...
        THESE_CRYSTALS_ARE_FOUND_ALL_OVER_VANA_DIEL                             = 10094,  -- These crystals are found all over Vana'diel, and their energies affect the surrounding ecosystems. Our research team had been investigating the unusual emanations when...
        GUESS_WHAT                                                              = 10095,  -- Guess what!
        WE_FINALLY_SUCCEEDED_IN_AWAKENING_THE_CRYSTALS                          = 10096,  -- We finally succeeded in awakening the crystals!
        OUR_THEORY_ON_WHAT_LAY_DORMANT_INSIDE_THE                               = 10097,  -- Our theory on what lay dormant inside the crystals was proven to be rightaru on the money! Except they didn't appreciate being woken up... We were attacked... We were bested-wested...
