        AND_TO_MAKE_THINGS_WORSE_NOBODY_BUDDY_ELSE                              = 10169,  -- And to make things worse, nobody-buddy else can enter the crystal with you! You'll be battling one-on-one, man-to-man, Taru-et-Taru!
        YES_BUT_SIR_THE_RHINOSTERY_HAS_BEEN_PRESSING                            = 10170,  -- ... Yes, but sir... The Rhinostery has been pressing us to produce results. If we do not take some sort of action quickly...
        HMMM_YOU_DO_HAVE_A_POINT_THERE_I                                        = 10171,  -- Hmmm... You do have a point there... I guess one round with a prime avatar wouldn't hurtaru.
