        ONLY_THOSE_FULFILLING_BOTH_REQUIREMENTS_SET_FORTH_BY                    = 10237,  -- Only those fulfilling both requirements set forth by the alliance may ride a chocobo. First, you must be a soldier of a respectable level in the Allied Forces. Secondly, you must be in possession of %.
        ANY_OF_OUR_FINE_BIRDS_HERE_WILL_BEAR                                    = 10238,  -- Any of our fine birds here will bear you directly to the frontlines of battle. We charge a service fee of # Allied Notes, which goes towards seeing that the chocobos are well taken care of. My records indicate that you currently have # Allied Notes.
