        I_TOLD_SANCTIA_OF_TWO_FAMOUS_BOUNTY_HUNTERS                             = 10511,  -- I told Sanctia of two famous bounty hunters: Goldmane of Tavnazia, and Ismenios Cutsilver of Bastok...
        THIS_PAIR_LEFT_THEIR_MARK_ON_VANA_DIEL                                  = 10512,  -- This pair left their mark on Vana'diel's history with the great deeds they performed twenty years ago.
        THEY_ARE_BEST_REMEMBERED_FOR_CAPTURING_THE_NOTORIOUS                    = 10513,  -- They are best remembered for capturing the notorious leader of Atarefaunet's Band and handing him over to the San d'Orian government.
        THE_SUM_THEY_RECEIVED_FOR_ATAREFAUNET_S_CAPTURE                         = 10514,  -- The sum they received for Atarefaunet's capture was said to have been unbelievably huge.
        SANCTIA_IS_PROBABLY_PLANNING_TO_APPRENTICE_HERSELF_TO                   = 10515,  -- Sanctia is probably planning to apprentice herself to Goldmane and make her fortune as a bounty hunter.
        I_HATE_TO_ADMIT_IT_BUT_HER_FATHER                                       = 10516,  -- I hate to admit it, but her father's debts would be impossible to pay back with any normal wage...
        ANYWAY_I_M_RELIEVED_TO_HEAR_SHE_S                                       = 10517,  -- Anyway, I'm relieved to hear she's not alone on her travels.
        THAT_MOOGLE_HAS_BEEN_ON_THE_ROAD_BEFORE                                 = 10518,  -- That moogle has been on the road before and knows which places to avoid.
        THAT_GOOD_FOR_NOTHING_CHELVADURAI_HIS_GAMBLING_HABITS                   = 10519,  -- That good-for-nothing Chelvadurai. His gambling habits are to blame for all this.
        I_LL_TELL_HIM_ABOUT_HIS_DAUGHTER_MYSELF                                 = 10520,  -- I'll tell him about his daughter myself. Here, you've done your part.
        I_LL_LET_CHELVADURAI_KNOW_WHAT_HAPPENED_TO                              = 10521,  -- I'll let Chelvadurai know what happened to his daughter.
        AND_I_LL_ALSO_GIVE_HIM_AN_EARFUL                                        = 10522,  -- And I'll also give him an earful about kicking his gambling habits.
        SANCTIA_STILL_HASN_T_RETURNED_TO_RABAO                                  = 10523,  -- Sanctia still hasn't returned to Rabao!?
        HER_FATHER_SAID_HE_WOULD_HIRE_THE_SERVICES                              = 10524,  -- Her father said he would hire the services of an adventurer, but I wonder if he even knows how to go about it?
        ZORIBOH_MENTIONED_HE_KNEW_THE_PERFECT_ADVENTURER_FOR                    = 10525,  -- Zoriboh mentioned he knew the perfect adventurer for the job, though...
