        SANCTIA_HASN_T_COME_BACK_FROM_TAVNAZIA_AND                              = 10527,  -- Sanctia hasn't come back from Tavnazia, and her father and I are worried.
        SHE_MUST_STILL_BE_LOOKING_FOR_GOLDMANE_THE                              = 10528,  -- She must still be looking for Goldmane, the bounty hunter I told you about.
        I_WANT_YOU_TO_FOLLOW_SANCTIA_AND_KEEP                                   = 10529,  -- I want you to follow Sanctia and keep her out of trouble until she either finds him or gives up on her search.
        WHAT_DO_YOU_SAY_I_LL_DO_IT                                              = 10530,  -- What do you say? I'll do it. I don't have time for babysitting.
        I_KNOW_SHE_S_A_HANDFUL_BUT_YOU                                          = 10531,  -- I know she's a handful, but you'll be well paid for your efforts.
        OH_AND_GIVE_THIS_TO_SANCTIA_WHEN_YOU                                    = 10532,  -- Oh, and give this to Sanctia when you find her.
