        TOO_BUSY_WITH_YOUR_ADVENTURES_TO_HELP_ANYONE                            = 10535,  -- Too busy with your adventures to help anyone, huh?
        LITTLE_SANCTIA_HAS_BECOME_AN_ADVENTURER                                 = 10536,  -- Little Sanctia has become an adventurer!?
        SO_GOLDMANE_CONVINCED_HER_THAT_WAS_THE_BEST                             = 10537,  -- So Goldmane convinced her that was the best path... Well, he'd be about the only person she'd listen to.
        BY_THE_WAY_DID_YOU_REMEMBER_TO_GIVE                                     = 10538,  -- By the way, did you remember to give Sanctia the package from her father?
