        THERE_IS_MORE_TO_THE_RUMOR_THAN_YOU                                     = 10553,  -- There is more to the rumor than you know. The branch and the thread that those monstrosities have swallowed are the base materials for a legendary fishing rod.
        SHOULD_YOU_MANAGE_TO_OBTAIN_THOSE_MATERIALS_BRING                       = 10554,  -- Should you manage to obtain those materials, bring them here to me. I am the only one left alive who can craft the rod of legend.
        INCREDIBLE_THIS_IS_A_FEAT_WORTHY_OF_THE                                 = 10555,  -- Incredible... This is a feat worthy of the greatest anglers in history.
        LEAVE_THESE_IN_MY_CARE_COME_TO_ME                                       = 10556,  -- Leave these in my care. Come to me again when the sun has passed through her cycle and you will be the first to witness an unbreakable spirit.
        PLEASE_DO_NOT_RUSH_ME_THE_CRAFTING_OF                                   = 10557,  -- Please, do not rush me. The crafting of a legend is not the work of mere moments.
        IT_IS_COMPLETE_I_MUST_THANK_YOU_FOR                                     = 10558,  -- It is complete. I must thank you for this chance to create such a masterpiece.
