        COME_ONE_COME_ALL_KUPO                                                  = 10561,  -- Come one, come all, kupo!
        GREETINGS_FRIEND_I_AM_A_SYNERGY_ENGINEER_DISPATCHED                     = 10562,  -- Greetings, friend! I am a synergy engineer, dispatched from the Institute to maintain the furnaces you see beside me. I also have knowledge and services to share with fellow synergists, if that is what you desire.
        I_SEE_FROM_THE_PUZZLED_EXPRESSION_ON_YOUR                               = 10563,  -- I see from the puzzled expression on your face that you are unfamiliar with our discipline. To use these furnaces, you will first need to obtain %.
        PIQUED_YOUR_CURIOSITY_HAVE_I_THEN_YOU_SHOULD                            = 10564,  -- Piqued your curiosity, have I? Then you should speak with Hildolf, our institute director, at his laboratory in the Bastok Metalworks. He's always eager to welcome a new synergist to our ranks.
        MAY_I_BE_OF_SERVICE_NOT_NOW_LEARN                                       = 10565,  -- May I be of service? Not now. Learn recipes. Check fewell. Replenish fewell. Purchase materials. Receive training. Trade cinder. Get information.
